-- Enrichment marathon batch: BorgBackup, Botify, BotWave, Boundary, Boxy SVG, Braintree, Brand24, Brandwatch

-- ── BorgBackup ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BorgBackup is a free, open-source deduplicating backup program for Linux, macOS, and BSD, combining space-efficient compression with authenticated 256-bit encryption.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BorgBackup: Free Open-Source Deduplicating Backup Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$BorgBackup is a free, open-source command-line backup tool with content-defined deduplication, compression, and authenticated encryption for Linux, macOS, and BSD.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BorgBackup (commonly called Borg) is a free, open-source deduplicating backup program released under the BSD 3-clause license. It was created in May 2015 when a group of contributors known as "The Borg Collective" forked Attic, an earlier deduplicating backup tool that began development in 2010, because Attic's original maintainer was slow to merge community contributions. Borg 1.0.0 was released on March 5, 2016, and the project has been actively maintained since, with a Borg 2.0 series in development as of 2026. Borg has no company behind it and no headquarters; it is a community-maintained open-source project hosted on GitHub, led by lead developer Thomas Waldmann. BorgBackup's core technical feature is content-defined chunking deduplication: each file is split into variable-length chunks, and only chunks not already present in the repository are stored, which makes daily incremental backups extremely space-efficient even across many similar files or snapshots. On top of deduplication, Borg applies client-side compression (choices include lz4, zstd, zlib, or lzma, or no compression) and authenticated 256-bit encryption using AES-OCB or ChaCha20-Poly1305, so data can be safely stored on untrusted or remote servers such as SSH-accessible storage, rsync.net, or BorgBase. Because encryption and chunking happen client-side, the backup destination never sees unencrypted data. Other notable features include the ability to mount a Borg archive as a regular filesystem using FUSE, letting users browse and restore individual files from a backup without extracting the entire archive; flexible pruning and retention policies for rotating old backups; and archive integrity verification. Borg runs natively on Linux, macOS, and FreeBSD/other BSD variants; it does not have official native Windows support, though it can be run inside WSL on Windows. There is no graphical installer or web dashboard bundled with core Borg — it is operated entirely from the command line, though third-party wrappers such as Borgmatic and Vorta provide scheduling and GUI layers on top of it. Because BorgBackup is free software with no paid tiers, there is no vendor pricing to evaluate; the only costs a user incurs are for whatever storage backend they choose to push encrypted archives to (a home server, NAS, cloud VM, or a Borg-compatible hosted service like BorgBase or rsync.net). BorgBackup is best suited to technically comfortable users — system administrators, DevOps engineers, and self-hosting enthusiasts — who want a scriptable, storage-efficient, and cryptographically sound backup solution for servers, workstations, or home labs, rather than end users looking for a polished consumer backup app with a graphical interface out of the box.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '156f6244-fa16-4f23-b785-7b39766ad2f0';

