-- ── Boundary ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Boundary is HashiCorp's open-source, identity-based secure remote access tool that grants least-privilege access to hosts and services without exposing the network.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-managed Community Edition)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$~2,180 employees (HashiCorp, an IBM company)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HashiCorp Boundary: Identity-Based Secure Remote Access$q$, seo_title),
  seo_meta_description = COALESCE($q$Boundary is HashiCorp's open-source tool for identity-based, zero-trust secure remote access to dynamic hosts and services, with a managed HCP option.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Boundary is an open-source secure remote access tool created by HashiCorp and first announced in October 2020. It provides identity-based access to dynamic hosts, services, and applications without requiring users to be granted direct network access (such as a traditional VPN) or to manage and distribute SSH keys and credentials manually. Instead of trusting a user based on their network location, Boundary authenticates and authorizes users centrally, then brokers just-in-time connections to targets — such as SSH servers, RDP hosts, databases, or internal web applications — based on identity and assigned roles, aligning with zero-trust security principles. HashiCorp, the company behind Boundary, was founded in 2012 by Mitchell Hashimoto and Armon Dadgar and is headquartered in San Francisco, California; as of 2026 the company has roughly 2,180 employees and became a wholly owned subsidiary of IBM after IBM's acquisition closed in February 2025 for $6.4 billion, though HashiCorp's product lines, including Boundary, continue to operate under the HashiCorp brand. Boundary is distributed in three main forms: a free, self-managed Community Edition released as open source software that provides core secure access controls, session management, and CLI/API/Terraform-based automation; a commercial Boundary Enterprise for self-managed enterprise deployments with additional governance and support; and HCP Boundary, a HashiCorp-managed cloud offering (generally available since November 2022) available in Standard and Plus tiers that removes the operational burden of running the control plane. Key technical features include dynamic host catalogs that automatically discover and keep an inventory of cloud and on-premises resources current, session visibility and recording for auditing connections after the fact, fine-grained role-based access policies, and integration with HashiCorp Vault for dynamic, short-lived credentials so users never see or store static secrets. Access can be initiated through the Boundary CLI, desktop client, REST API, Terraform provider, or SDKs, making it scriptable for DevOps and platform engineering workflows. HCP Boundary is billed on a usage basis, metered by "HCP Boundary Users" — each unique human or machine identity that takes an authenticated action within a given month — with the per-user rate varying by the Standard or Plus edition chosen; HashiCorp does not publish exact per-user dollar rates on its public pricing page, so buyers must engage with sales or the HCP portal for a quote. Boundary is aimed at DevOps, platform engineering, and security teams that need to grant developers, operators, or automated systems access to dynamic, frequently-changing infrastructure (cloud VMs, containers, databases) without exposing the underlying network, and who are often already using other HashiCorp tools like Vault, Terraform, or Consul as part of their infrastructure stack.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'af04c60a-0edd-428f-9f5c-f88f9ad98f64';

