-- ── Boxy SVG ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Boxy SVG is a lightweight vector graphics editor for creating and editing SVG files, available free in-browser and as a paid desktop app for Mac, Windows, and Linux.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Solo developer (independent software)$q$, company_size),
  headquarters = COALESCE($q$Warsaw, Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Boxy SVG: Vector & SVG Editor for Mac, Windows, and Web$q$, seo_title),
  seo_meta_description = COALESCE($q$Boxy SVG is a lightweight vector graphics editor for creating and editing SVG files, with on-canvas tools, a code view, and apps for Mac, Windows, Linux, and web.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Boxy SVG is a vector graphics editor built specifically around the SVG (Scalable Vector Graphics) file format, created by independent developer Jarek Foksa, who is based in Warsaw, Poland. The first version shipped on the Mac App Store on March 15, 2013, originally written in Objective-C and CoffeeScript. A complete rewrite followed on August 1, 2014, moving the codebase to JavaScript and Electron so the same application could run both as a web app in the browser and as a native desktop app, and a further UI overhaul shipped June 6, 2017 based on Xel, Foksa's own HTML5 widget toolkit. Because it is built and maintained by a solo developer rather than a company, Boxy SVG has no formal headquarters, corporate structure, or public employee count in the conventional sense; its interface is inspired by design tools like Inkscape, Sketch, and Adobe Illustrator. The editor's Chromium-based rendering engine gives it an SVG and CSS code inspector similar to Chrome DevTools, and the app preserves clean SVG output — including metadata like element IDs, classes, and titles — rather than bloating exported files with editor-specific cruft, a common complaint about some competing vector tools. Core editing capabilities include on-canvas manipulation of object geometry, transforms, paint, and other SVG properties; a built-in code view for editing raw SVG markup alongside the visual canvas; path Boolean operations (unite, intersect, subtract, exclude) and other path tools; manual guides, smart guides, and a configurable grid; over 100 configurable keyboard shortcuts; integration with Pixabay for access to over a million free stock photos and vector assets; and Google Fonts integration for typography. Export formats include SVG, SVGZ (compressed SVG), PNG, JPG, WebP, PDF, and HTML5. Boxy SVG runs as a free web app directly in the browser, covering basic SVG editing (shapes, paths, text, gradients, groups) at no cost, and is also distributed as a native desktop app for macOS (via the Mac App Store, priced at $19.99 as a one-time purchase, confirmed on the App Store listing) and for Windows (via the Microsoft Store) and Linux/Chrome OS. Boxy SVG has also introduced a premium web subscription tier — reported by third-party sources at roughly $9.99 per year or per month depending on the plan — that unlocks additional capabilities such as advanced CSS styling and JavaScript editing, along with additional export formats, though the exact current pricing structure for the web premium tiers is best confirmed directly on boxy-svg.com since third-party sources report some inconsistency in the figures. Boxy SVG is best suited to web designers, front-end developers, and hobbyists who need a focused, lightweight SVG editor with direct code-level control, rather than a full-featured illustration or raster-editing suite like Adobe Illustrator or Affinity Designer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e093e26f-1179-4cad-b7f0-010ea97f3788';

