-- ── Braintree ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Braintree, a PayPal service, is a payment gateway that lets businesses accept cards, PayPal, Venmo, and digital wallets through a single API integration.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based (per transaction)$q$, pricing_model),
  starting_price = COALESCE($q$2.9% + $0.30 per transaction$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Braintree: PayPal's Payment Gateway & Merchant API$q$, seo_title),
  seo_meta_description = COALESCE($q$Braintree, owned by PayPal, is a payment processing platform offering one API for cards, PayPal, Venmo, Apple Pay, and Google Pay, processing $50B+ annually.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Braintree is a payment processing platform founded by Bryan Johnson in 2007 and headquartered in Chicago, Illinois. PayPal acquired Braintree in 2013 for approximately $800 million, and Braintree has operated as a PayPal service ever since, giving it access to PayPal's broader payments infrastructure, risk management systems, and global reach while continuing to operate its own developer-focused brand and product line. Braintree's core value proposition is a single API integration that lets merchants accept a wide range of payment methods — credit and debit cards, PayPal, Venmo, Apple Pay, Google Pay, and other digital wallets — without having to build and maintain separate integrations for each. This makes it popular with software companies, marketplaces, and platforms that want to offer flexible checkout options to their end customers without the engineering overhead of integrating each payment method individually. The platform provides native SDKs for iOS and Android as well as JavaScript SDKs for web, which supports both custom checkout UIs and Braintree's pre-built Drop-in UI for faster implementation. Additional features include recurring billing and subscription management, a Vault for securely storing customer payment methods for future use (supporting card-on-file and tokenized transactions), and fraud and risk management tools built on PayPal's underlying fraud detection infrastructure. Braintree's standard published pricing for U.S. merchants is 2.9% of the transaction amount plus $0.30 per transaction, a rate broadly comparable to other major payment processors like Stripe; established or high-volume businesses can negotiate custom flat-rate or interchange-plus pricing instead of the standard blended rate. Additional standard fees include a $15 chargeback fee per disputed transaction, along with adjustments for international transactions, non-profit/charitable organizations, and certain other transaction types. Braintree reports processing more than $50 billion in payment volume annually and over one billion transactions per quarter, reflecting its use by a large base of e-commerce and platform businesses. Merchants must go through an approval and underwriting process before they can process live transactions, which is standard for full-service payment gateways handling PCI-sensitive card data, but can add friction compared to some simpler payment button integrations. Braintree is best suited for e-commerce businesses, software platforms and marketplaces that need to split or route payments to multiple parties, and subscription/SaaS businesses that need robust recurring billing — particularly those that want to offer PayPal, Venmo, and digital wallets alongside cards without managing multiple separate payment integrations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '633df78b-c6d3-45d8-a067-207679f3055d';

