-- ── Brand24 ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Brand24 is an AI-powered social listening and media monitoring tool that tracks brand mentions across social media, news, blogs, and forums in real time.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$199/month billed annually ($249/month billed monthly)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Wrocław, Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Brand24: AI Social Listening & Brand Monitoring Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Brand24 is an AI-powered social listening platform that tracks brand mentions across social media, news, and forums, with sentiment analysis and real-time alerts.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Brand24 is a social listening and media monitoring platform founded in 2011 by Michal Sadowski and headquartered in Wrocław, Poland. The company is publicly traded on the Warsaw Stock Exchange and is majority-owned by Prowly, itself a subsidiary of Semrush, the American SEO and marketing analytics company. Brand24's core function is to track online mentions of a brand, product, competitor, or topic across social media platforms, news sites, blogs, forums, podcasts, videos, and review sites, aggregating them into a single dashboard. The platform has increasingly emphasized AI-driven analysis, including AI sentiment analysis that automatically classifies mentions as positive, negative, or neutral; an AI Brand Assistant; AI Insights and AI Topics features that summarize themes and trends across large volumes of mentions; and AI Events Detection for spotting sudden spikes or anomalies in mention volume, such as a PR crisis or viral moment. Additional capabilities include influencer scoring to identify which authors are driving the most reach or engagement, share-of-voice and trend analysis for competitive benchmarking, and integrations with tools like Slack and Google Data Studio for reporting and alerting. Brand24 publishes its pricing transparently on its website, structured around five tiers. The Individual plan starts at $199/month billed annually (or $249/month billed monthly) and covers 3 keywords, roughly 2,000 mentions per month, 1 user, and updates every 12 hours. The Team plan is $299/month annually ($349 monthly), covering 7 keywords, 10,000 mentions/month, unlimited users, and hourly updates. The Pro plan is $399/month annually ($499 monthly), covering 12 keywords, 40,000 mentions/month, unlimited users, real-time updates, and the fuller AI feature set (AI Events Detection, AI Brand Assistant, AI Insights and AI Topics for a limited number of projects). The Business plan is $599/month annually ($699 monthly), covering 25 keywords, 100,000 mentions/month, and expanded AI Insights/Topics access plus a dedicated Client Success Lead. An Enterprise plan offers custom keyword and mention limits with unlimited AI Insights and Topics, dedicated consulting, and an AI Visibility module, with pricing starting around $1,499 and scaling by negotiated agreement. All paid plans are backed by a 14-day free trial that does not require a credit card. Brand24 is generally positioned as a more accessible, mid-market alternative to larger enterprise social listening suites like Brandwatch or Meltwater, making it popular with small and medium businesses, marketing agencies managing multiple client brands, and PR teams that need real-time crisis and reputation monitoring without an enterprise sales process.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '70a19bf7-581a-4046-9e3d-4778823d9374';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '70a19bf7-581a-4046-9e3d-4778823d9374' AND logo IS NULL AND website IS NOT NULL;

DELETE FROM tool_features WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';

DELETE FROM tool_pros WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';

DELETE FROM tool_cons WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';

DELETE FROM tool_faqs WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';

DELETE FROM tool_use_cases WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';

DELETE FROM tool_pricing_plans WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';

DELETE FROM tool_content_blocks WHERE tool_id = '70a19bf7-581a-4046-9e3d-4778823d9374';


-- ── Brandwatch ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Brandwatch is an AI-powered consumer intelligence and social media management platform, owned by Cision, that analyzes conversations across 100M+ online sources.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (Custom/Enterprise)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$1,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Brighton, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Brandwatch: AI Consumer Intelligence & Social Listening$q$, seo_title),
  seo_meta_description = COALESCE($q$Brandwatch is an enterprise consumer intelligence and social media management platform owned by Cision, analyzing 100M+ online sources for brand insights.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Brandwatch is an enterprise consumer intelligence and social media management platform founded by Giles Palmer, who incorporated the predecessor company Runtime Collective Ltd in Brighton, UK, in 1999/2005; the business relaunched its social monitoring product as Brandwatch in 2007, focusing on tracking social media mentions and measuring social advertising impact. The company remains headquartered in Brighton, United Kingdom, and has grown to more than 1,000 employees across roughly 15-17 offices worldwide, including New York, London, Copenhagen, Berlin, Sofia, Paris, Singapore, and Sydney. In February 2021, Brandwatch was acquired by Cision, the PR and media monitoring company, for $450 million in a combined cash-and-shares deal, combining Brandwatch's social listening and consumer intelligence capabilities with Cision's media monitoring and press/media contact database business. Brandwatch has continued to operate under its own brand post-acquisition rather than being folded into the Cision name. In May 2022, Falcon.io — a social media management platform Cision had acquired in January 2019 — was merged into Brandwatch, meaning social media publishing, engagement, and scheduling tools formerly sold under the Falcon.io brand now live within Brandwatch's Social Media Management product line. Brandwatch today sells two main product lines: Consumer Intelligence and Social (Social Media Management). Consumer Intelligence itself comprises Consumer Research (which mines social media and other online data from more than 100 million sources for market research and brand-perception analysis), Vizia (a data visualization add-on for displaying live social/brand metrics on screens, often used in newsrooms or marketing operations centers), and Reviews (a product review monitoring and analysis tool). The platform emphasizes AI-driven analytics for large-scale conversation and sentiment analysis, image/visual listening to detect logos and visual brand mentions in photos, and trend and topic detection across its massive data footprint. Brandwatch reports serving more than 7,500 clients and states it is trusted by roughly half of the Forbes 100. As is typical for platforms operating at this scale and data volume, Brandwatch does not publish self-serve pricing; access requires a custom quote from its sales team based on data volume, modules licensed, and number of seats, positioning it as a premium, enterprise-first option relative to lower-cost self-serve social listening tools. Brandwatch also offers a public developer API — the Brandwatch API, covering Consumer Research, Publish, Engage, Measure, Data Upload, and Analysis endpoints, documented at developers.brandwatch.com — that lets enterprise customers pull mention, sentiment, and trend data into their own systems and BI tooling, though usage is rate-limited (30 calls per 10 minutes per client by default). Brandwatch is best suited to large enterprises, market research teams, and PR/communications agencies that need very large-scale social and consumer data coverage, dedicated onboarding, and combined listening-plus-publishing capabilities, rather than smaller teams looking for simpler, self-serve pricing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '76c85988-2b96-4585-b424-bd7aa44ecb82';

